/**
 * Retrieves the price of a product from the API or local storage.
 * 
 * @param {string|number} productId - The ID of the product.
 * @returns {Promise<number>} A promise that resolves to the price of the product.
 */
async function getPrice(productId) {
  // Check if the price is cached in local storage
  const cached = localStorage.getItem(`price_${productId}`);
  if (cached !== null) {
    // Attempt to parse the cached price as a float
    const cachedPrice = parseFloat(cached);
    if (!isNaN(cachedPrice)) {
      return cachedPrice;
    }
  }

  try {
    // Fetch the price from the API
    const res = await fetch(`/api/price/${productId}`);

    // Check if the response was successful
    if (!res.ok) {
      throw new Error(`Failed to retrieve price: ${res.status} ${res.statusText}`);
    }

    // Parse the response as JSON
    const data = await res.json();

    // Check if the response contains a valid price
    if (typeof data !== 'number') {
      throw new Error('Invalid price response');
    }

    // Store the price in local storage as a string
    localStorage.setItem(`price_${productId}`, data.toString());

    return data;
  } catch (error) {
    // Log or handle the error as needed
    // For example, you could rethrow it or return a default value
    console.error(`Error retrieving price: ${error.message}`);
    throw error;
  }
}
```

